previewCss:
.darma-loader-darma-custom-108 {
  width: 20px;
  aspect-ratio: 1;
  background: var(--loader-color, #514b82);
  position: relative;
  transform-origin: top right;
  animation: darma-loader-darma-custom-108-l28-0 2s infinite linear;
}
.darma-loader-darma-custom-108:before,
.darma-loader-darma-custom-108:after {
  content: "";
  position: absolute;
  width: 100%;
  height: 100%;
  background: inherit; 
  transform-origin: bottom right;
  clip-path: polygon(0 0,100% 100%,0 100%);
  inset: auto auto 100% 0;
  animation: darma-loader-darma-custom-108-l28-1 1s infinite linear alternate;
}
.darma-loader-darma-custom-108:after {
  inset: auto auto 0 100%;
  transform-origin: top left;
  --s:-1;
}
@keyframes darma-loader-darma-custom-108-l28-0 {
 0% ,49.99% {transform:scale(1)}
 50%,90%    {transform:scale(-1)}
 100%       {transform:scale(-1) rotate(180deg)}
}
@keyframes darma-loader-darma-custom-108-l28-1 {
 0% ,30%   {transform:rotate(calc(var(--s,1)*0))}
 70%,100%  {transform:rotate(calc(var(--s,1)*90deg))}
}

